import React, { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { toast } from "react-toastify";
import {
  buscarEntrega,
  criarEntrega,
  atualizarEntrega,
} from "../../services/entregaService";
import { listarTipos } from "../../services/tipoEntregaService";

const STATUS_OPTIONS = [
  { value: "pendente",    label: "Pendente" },
  { value: "em_transito", label: "Em trânsito" },
  { value: "entregue",   label: "Entregue" },
  { value: "cancelado",  label: "Cancelado" },
];

const EMPTY_FORM = {
  nomeRemetente: "",
  nomeDestinatario: "",
  enderecoDestino: "",
  tipoEntregaId: "",
  dataPostagem: "",
  status: "pendente",
};

export default function EntregaForm() {
  const { id } = useParams();
  const navigate = useNavigate();
  const isEditing = Boolean(id);

  const [form, setForm] = useState(EMPTY_FORM);
  const [tipos, setTipos] = useState([]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    // Load tipos de entrega
    listarTipos()
      .then((res) => setTipos(res.data))
      .catch(() => toast.error("Erro ao carregar tipos de entrega."));

    if (isEditing) {
      setLoading(true);
      buscarEntrega(id)
        .then((res) => {
          const e = res.data;
          setForm({
            nomeRemetente: e.nomeRemetente || "",
            nomeDestinatario: e.nomeDestinatario || "",
            enderecoDestino: e.enderecoDestino || "",
            tipoEntregaId: e.tipoEntregaId || "",
            dataPostagem: e.dataPostagem ? e.dataPostagem.slice(0, 10) : "",
            status: e.status || "pendente",
          });
        })
        .catch(() => toast.error("Erro ao carregar entrega."))
        .finally(() => setLoading(false));
    }
  }, [id, isEditing]);

  function handleChange(e) {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  }

  async function handleSubmit(e) {
    e.preventDefault();

    if (!form.nomeRemetente.trim()) {
      toast.warning("Informe o nome do remetente.");
      return;
    }
    if (!form.nomeDestinatario.trim()) {
      toast.warning("Informe o nome do destinatário.");
      return;
    }
    if (!form.tipoEntregaId) {
      toast.warning("Selecione o tipo de entrega.");
      return;
    }
    if (!form.dataPostagem) {
      toast.warning("Informe a data de postagem.");
      return;
    }

    try {
      setSaving(true);
      const payload = {
        nomeRemetente: form.nomeRemetente.trim(),
        nomeDestinatario: form.nomeDestinatario.trim(),
        enderecoDestino: form.enderecoDestino.trim(),
        tipoEntregaId: Number(form.tipoEntregaId),
        dataPostagem: form.dataPostagem,
        status: form.status,
      };

      if (isEditing) {
        await atualizarEntrega(id, payload);
        toast.success("Entrega atualizada com sucesso!");
      } else {
        await criarEntrega(payload);
        toast.success("Entrega cadastrada com sucesso!");
      }
      navigate("/entregas");
    } catch {
      toast.error("Erro ao salvar entrega.");
    } finally {
      setSaving(false);
    }
  }

  if (loading) {
    return (
      <div style={{ padding: 32 }}>
        {[1, 2, 3, 4].map((n) => (
          <div
            key={n}
            className="shimmer-row"
            style={{ maxWidth: 500, marginBottom: 12 }}
          />
        ))}
      </div>
    );
  }

  return (
    <div className="form-card">
      <div className="form-card-header">
        <i className="bi bi-box-seam" />
        {isEditing ? "Editar Entrega" : "Nova Entrega"}
      </div>

      <form className="form-card-body" onSubmit={handleSubmit}>
        {/* Remetente */}
        <div style={{ marginBottom: 16 }}>
          <label className="form-label-custom">
            Remetente <span style={{ color: "var(--danger)" }}>*</span>
          </label>
          <input
            className="form-control-custom"
            name="nomeRemetente"
            value={form.nomeRemetente}
            onChange={handleChange}
            placeholder="Nome de quem envia"
          />
        </div>

        {/* Destinatário */}
        <div style={{ marginBottom: 16 }}>
          <label className="form-label-custom">
            Destinatário <span style={{ color: "var(--danger)" }}>*</span>
          </label>
          <input
            className="form-control-custom"
            name="nomeDestinatario"
            value={form.nomeDestinatario}
            onChange={handleChange}
            placeholder="Nome de quem recebe"
          />
        </div>

        {/* Endereço */}
        <div style={{ marginBottom: 16 }}>
          <label className="form-label-custom">Endereço de Destino</label>
          <input
            className="form-control-custom"
            name="enderecoDestino"
            value={form.enderecoDestino}
            onChange={handleChange}
            placeholder="Rua, número, cidade..."
          />
        </div>

        {/* Tipo de Entrega */}
        <div style={{ marginBottom: 16 }}>
          <label className="form-label-custom">
            Tipo de Entrega <span style={{ color: "var(--danger)" }}>*</span>
          </label>
          <select
            className="form-control-custom"
            name="tipoEntregaId"
            value={form.tipoEntregaId}
            onChange={handleChange}
          >
            <option value="">Selecione...</option>
            {tipos.map((t) => (
              <option key={t.id} value={t.id}>
                {t.descricao} ({t.prazoEmDias}{" "}
                {t.prazoEmDias === 1 ? "dia" : "dias"})
              </option>
            ))}
          </select>
          <div className="form-hint">
            A data prevista de entrega será calculada automaticamente pelo
            sistema.
          </div>
        </div>

        {/* Data de Postagem */}
        <div style={{ marginBottom: 16 }}>
          <label className="form-label-custom">
            Data de Postagem <span style={{ color: "var(--danger)" }}>*</span>
          </label>
          <input
            className="form-control-custom"
            name="dataPostagem"
            type="date"
            value={form.dataPostagem}
            onChange={handleChange}
          />
        </div>

        {/* Status */}
        <div style={{ marginBottom: 16 }}>
          <label className="form-label-custom">Status</label>
          <select
            className="form-control-custom"
            name="status"
            value={form.status}
            onChange={handleChange}
          >
            {STATUS_OPTIONS.map((s) => (
              <option key={s.value} value={s.value}>
                {s.label}
              </option>
            ))}
          </select>
        </div>

        <div className="form-actions">
          <button
            className="btn-primary-custom"
            type="submit"
            disabled={saving}
          >
            {saving ? (
              <>
                <span
                  className="spinner-border spinner-border-sm"
                  style={{ marginRight: 6 }}
                />
                Salvando...
              </>
            ) : (
              <>
                <i className="bi bi-check-lg" />
                {isEditing ? "Salvar alterações" : "Cadastrar"}
              </>
            )}
          </button>
          <button
            className="btn-secondary-custom"
            type="button"
            onClick={() => navigate("/entregas")}
          >
            Cancelar
          </button>
        </div>
      </form>
    </div>
  );
}
